24	func TestEfficacyRowsReadsSessionIndexAsStrictSupersetOfLegacyEvidence(t *testing.T) {
25		workDir := t.TempDir()
26		store := bead.NewStore(filepath.Join(workDir, ddxroot.DirName))
27		closed := &bead.Bead{Title: "closed legacy evidence", Status: bead.StatusOpen}
28		if err := store.Create(closed); err != nil {
29			t.Fatal(err)
30		}
31		if err := store.AppendEvent(closed.ID, bead.BeadEvent{Kind: "routing", Body: `{"harness":"codex","resolved_provider":"openai","resolved_model":"gpt-5"}`}); err != nil {
32			t.Fatal(err)
33		}
34		if err := store.AppendEvent(closed.ID, bead.BeadEvent{Kind: "cost", Body: `{"harness":"codex","provider":"openai","model":"gpt-5","input_tokens":100,"output_tokens":50,"duration_ms":1000,"cost_usd":0.01,"exit_code":0}`}); err != nil {
35			t.Fatal(err)
36		}
37		if err := store.Close(closed.ID); err != nil {
38			t.Fatal(err)
39		}
40		open := &bead.Bead{Title: "open bead session", Status: bead.StatusOpen}
41		if err := store.Create(open); err != nil {
42			t.Fatal(err)
43		}
44	
45		now := time.Date(2026, 4, 22, 12, 0, 0, 0, time.UTC)
46		appendSessionForTest(t, workDir, agent.SessionIndexEntry{ID: "closed-session", BeadID: closed.ID, Harness: "codex", Provider: "openai", Model: "gpt-5", StartedAt: now, DurationMS: 1000, CostUSD: 0.01, CostPresent: true, InputTokens: 100, OutputTokens: 50, Outcome: "success", BundlePath: ".ddx/executions/closed-session"}, now)
47		appendSessionForTest(t, workDir, agent.SessionIndexEntry{ID: "open-bead-session", BeadID: open.ID, Harness: "agent", Provider: "openai", Model: "gpt-5.4", StartedAt: now.Add(time.Minute), DurationMS: 2000, InputTokens: 200, OutputTokens: 70, Outcome: "success", BundlePath: ".ddx/executions/open-bead-session"}, now.Add(time.Minute))
48		appendSessionForTest(t, workDir, agent.SessionIndexEntry{ID: "agent-run-session", Harness: "agent-run", Provider: "anthropic", Model: "claude-sonnet-4-6", StartedAt: now.Add(2 * time.Minute), DurationMS: 3000, InputTokens: 300, OutputTokens: 80, Outcome: "success", NativeLogRef: ".ddx/agent-logs/agent-run-session.jsonl"}, now.Add(2*time.Minute))
49		appendSessionForTest(t, workDir, agent.SessionIndexEntry{ID: "benchmark-session", Harness: "benchmark", Provider: "local", Model: "qwen3.5-27b", StartedAt: now.Add(3 * time.Minute), DurationMS: 4000, InputTokens: 400, OutputTokens: 90, Outcome: "failure", Detail: "benchmark failed"}, now.Add(3*time.Minute))
50	
51		rows, err := (&queryResolver{Resolver: &Resolver{WorkingDir: workDir}}).EfficacyRows(context.Background(), nil, nil, nil, nil)
52		if err != nil {
53			t.Fatal(err)
54		}
55		got := map[string]*EfficacyRow{}
56		for _, row := range rows {
57			got[row.RowKey] = row
58		}
59		legacy := legacyEfficacyRowKeysForTest(t, store)
60		for key := range legacy {
61			if _, ok := got[key]; !ok {
62				t.Fatalf("new session efficacy output missing legacy key %q; got %v", key, sortedKeys(got))
63			}
64		}
65		for _, key := range []string{
66			"agent|openai|gpt-5.4",
67			"agent-run|anthropic|claude-sonnet-4-6",
68			"benchmark|local|qwen3.5-27b",
69		} {
70			if _, ok := legacy[key]; ok {
71				t.Fatalf("test setup error: legacy evidence unexpectedly contains %q", key)
72			}
73			if _, ok := got[key]; !ok {
74				t.Fatalf("new session efficacy output missing session-only key %q; got %v", key, sortedKeys(got))
75			}
76		}
77		if len(got) <= len(legacy) {
78			t.Fatalf("new output is not a strict superset: legacy=%v got=%v", sortedSet(legacy), sortedKeys(got))
79		}
80	}
