160	func TestEfficacyRowsDateFilterAndPerfTargets(t *testing.T) {
161		if raceEnabled {
162			t.Skip("perf thresholds are measured without the race detector")
163		}
164		workDir := t.TempDir()
165		now := time.Now().UTC()
166		seedEfficacySessionFixture(t, workDir, 10_000, 2, now)
167		resolver := &queryResolver{Resolver: &Resolver{WorkingDir: workDir}}
168		ctx := context.Background()
169	
170		allTimeInProcess := measureP95(20, func() {
171			if rows, err := resolver.EfficacyRows(ctx, nil, nil, nil, nil); err != nil {
172				t.Fatal(err)
173			} else if len(rows) < 10 {
174				t.Fatalf("fixture produced %d rows, want >= 10", len(rows))
175			}
176		})
177		if allTimeInProcess > 300*time.Millisecond {
178			t.Fatalf("10k all-time in-process p95=%s, want <=300ms", allTimeInProcess)
179		}
180	
181		since := now.AddDate(0, 0, -30).Format(time.RFC3339)
182		filteredInProcess := measureP95(20, func() {
183			if rows, err := resolver.EfficacyRows(ctx, &since, nil, nil, nil); err != nil {
184				t.Fatal(err)
185			} else if len(rows) < 10 {
186				t.Fatalf("date-filter fixture produced %d rows, want >= 10", len(rows))
187			}
188		})
189		if filteredInProcess > 120*time.Millisecond {
190			t.Fatalf("10k last-30-days in-process p95=%s, want <=120ms", filteredInProcess)
191		}
192	
193		httpHandler := efficacyHTTPHandler(workDir)
194		allTimeHTTP := measureP95(12, func() {
195			graphqlPOSTForTest(t, httpHandler, `{ efficacyRows { rowKey attempts successes successRate medianInputTokens medianOutputTokens medianDurationMs medianCostUsd } }`)
196		})
197		if allTimeHTTP > 800*time.Millisecond {
198			t.Fatalf("10k all-time HTTP p95=%s, want <=800ms", allTimeHTTP)
199		}
200		filteredHTTP := measureP95(12, func() {
201			graphqlPOSTForTest(t, httpHandler, fmt.Sprintf(`{ efficacyRows(since: %q) { rowKey attempts } }`, since))
202		})
203		if filteredHTTP > 400*time.Millisecond {
204			t.Fatalf("10k last-30-days HTTP p95=%s, want <=400ms", filteredHTTP)
205		}
206	
207		stretchDir := t.TempDir()
208		seedEfficacySessionFixture(t, stretchDir, 50_000, 24, now)
209		stretchResolver := &queryResolver{Resolver: &Resolver{WorkingDir: stretchDir}}
210		stretchInProcess := measureP95(10, func() {
211			if rows, err := stretchResolver.EfficacyRows(ctx, nil, nil, nil, nil); err != nil {
212				t.Fatal(err)
213			} else if len(rows) < 10 {
214				t.Fatalf("stretch fixture produced %d rows, want >= 10", len(rows))
215			}
216		})
217		if stretchInProcess > 800*time.Millisecond {
218			t.Fatalf("50k stretch all-time in-process p95=%s, want <=800ms", stretchInProcess)
219		}
220		stretchHTTPHandler := efficacyHTTPHandler(stretchDir)
221		stretchHTTP := measureP95(8, func() {
222			graphqlPOSTForTest(t, stretchHTTPHandler, `{ efficacyRows { rowKey attempts successes successRate medianDurationMs } }`)
223		})
224		if stretchHTTP > 2*time.Second {
225			t.Fatalf("50k stretch all-time HTTP p95=%s, want <=2000ms", stretchHTTP)
226		}
227		t.Logf("efficacy perf baseline: 10k all-time in-process p95=%s http p95=%s; last30 in-process p95=%s http p95=%s; 50k/24-shard all-time in-process p95=%s http p95=%s", allTimeInProcess, allTimeHTTP, filteredInProcess, filteredHTTP, stretchInProcess, stretchHTTP)
228	}
