230	// TestEfficacyRowsSmokeOverRealBackend is the backend half of the
231	// AC §8 Playwright smoke: it seeds the same 10k-session index fixture the
232	// frontend smoke mirrors (see cli/internal/server/frontend/e2e/efficacy.spec.ts
233	// "smoke: efficacy opens with 10k-session rollup fixture"), then drives the
234	// real GraphQL HTTP handler end-to-end — first EfficacyRows, then
235	// EfficacyAttempts for the first row returned (the "click into the row"
236	// gesture). Together with the Playwright smoke they form the ddx-0a33bc5f
237	// equivalent of the beads smoke pair (Playwright UI mock +
238	// cli/internal/server/perf/smoke_test.go real-backend ceiling).
239	func TestEfficacyRowsSmokeOverRealBackend(t *testing.T) {
240		workDir := t.TempDir()
241		now := time.Now().UTC()
242		seedEfficacySessionFixture(t, workDir, 10_000, 2, now)
243	
244		httpHandler := efficacyHTTPHandler(workDir)
245		rowsResp := graphqlPOSTForTestReturningBody(t, httpHandler, `{ efficacyRows { rowKey harness provider model attempts successes successRate medianDurationMs medianCostUsd sparkline } }`)
246		var rowsData struct {
247			Data struct {
248				EfficacyRows []struct {
249					RowKey           string   `json:"rowKey"`
250					Attempts         int      `json:"attempts"`
251					Successes        int      `json:"successes"`
252					SuccessRate      float64  `json:"successRate"`
253					MedianDurationMs int      `json:"medianDurationMs"`
254					MedianCostUsd    *float64 `json:"medianCostUsd"`
255					Sparkline        []int    `json:"sparkline"`
256				} `json:"efficacyRows"`
257			} `json:"data"`
258		}
259		if err := json.Unmarshal(rowsResp, &rowsData); err != nil {
260			t.Fatalf("decode efficacyRows: %v body=%s", err, rowsResp)
261		}
262		if got := len(rowsData.Data.EfficacyRows); got < 5 {
263			t.Fatalf("expected at least 5 efficacy rows from the 10k fixture, got %d", got)
264		}
265		if got := len(rowsData.Data.EfficacyRows[0].Sparkline); got != 24 {
266			t.Fatalf("expected 24 sparkline buckets in real-backend smoke, got %d", got)
267		}
268	
269		firstRowKey := rowsData.Data.EfficacyRows[0].RowKey
270		start := time.Now()
271		attemptsResp := graphqlPOSTForTestReturningBody(t, httpHandler, fmt.Sprintf(`{ efficacyAttempts(rowKey: %q) { rowKey attempts { beadId outcome durationMs costUsd evidenceBundleUrl } } }`, firstRowKey))
272		clickInto := time.Since(start)
273		var attemptsData struct {
274			Data struct {
275				EfficacyAttempts struct {
276					RowKey   string `json:"rowKey"`
277					Attempts []struct {
278						BeadID            string   `json:"beadId"`
279						Outcome           string   `json:"outcome"`
280						DurationMs        int      `json:"durationMs"`
281						CostUsd           *float64 `json:"costUsd"`
282						EvidenceBundleURL string   `json:"evidenceBundleUrl"`
283					} `json:"attempts"`
284				} `json:"efficacyAttempts"`
285			} `json:"data"`
286		}
287		if err := json.Unmarshal(attemptsResp, &attemptsData); err != nil {
288			t.Fatalf("decode efficacyAttempts: %v body=%s", err, attemptsResp)
289		}
290		if attemptsData.Data.EfficacyAttempts.RowKey != firstRowKey {
291			t.Fatalf("efficacyAttempts returned rowKey %q, want %q", attemptsData.Data.EfficacyAttempts.RowKey, firstRowKey)
292		}
293		if len(attemptsData.Data.EfficacyAttempts.Attempts) == 0 {
294			t.Fatalf("efficacyAttempts(%q) returned no attempts", firstRowKey)
295		}
296		// "Normal navigation budget": a click-into request against the already-
297		// warmed cache must stay well under one second. This is a regression
298		// ceiling, not a p95 target.
299		if clickInto > time.Second {
300			t.Fatalf("efficacyAttempts click-into took %s, exceeding the 1s navigation ceiling", clickInto)
301		}
302		t.Logf("efficacy real-backend smoke: rows=%d firstRowKey=%s clickInto=%s", len(rowsData.Data.EfficacyRows), firstRowKey, clickInto)
303	}
