368	func seedEfficacySessionFixture(t *testing.T, workDir string, count, shards int, now time.Time) {
369		t.Helper()
370		logDir := agent.SessionLogDirForWorkDir(workDir)
371		if err := os.MkdirAll(agent.SessionIndexDir(logDir), 0o755); err != nil {
372			t.Fatal(err)
373		}
374		groups := []struct {
375			harness  string
376			provider string
377			model    string
378		}{
379			{"agent", "openai", "gpt-5.4"},
380			{"agent", "openai", "gpt-5.4-mini"},
381			{"codex", "openai", "gpt-5.3-codex"},
382			{"claude", "anthropic", "claude-sonnet-4-6"},
383			{"claude", "anthropic", "claude-opus-4-6"},
384			{"gemini", "google", "gemini-2.5-pro"},
385			{"benchmark", "local", "qwen3.5-27b"},
386			{"quorum", "openrouter", "minimax/minimax-m2.7"},
387			{"agent-run", "moonshot", "moonshot/kimi-k2.5"},
388			{"script", "vidar", "qwen/qwen3-coder-next"},
389		}
390		type shardWriter struct {
391			file *os.File
392			enc  *json.Encoder
393		}
394		writers := map[string]shardWriter{}
395		defer func() {
396			for _, writer := range writers {
397				_ = writer.file.Close()
398			}
399		}()
400		projectID := agent.ProjectIDForPath(workDir)
401		current := time.Date(now.Year(), now.Month(), 1, 12, 0, 0, 0, time.UTC)
402		for i := 0; i < count; i++ {
403			shardOffset := i % shards
404			var ts time.Time
405			if shardOffset == 0 {
406				ts = now.Add(-time.Duration(i%5000) * time.Minute)
407			} else {
408				ts = current.AddDate(0, -shardOffset-1, 0).Add(time.Duration(i%720) * time.Minute)
409			}
410			path := agent.SessionIndexShardPath(logDir, ts)
411			writer, ok := writers[path]
412			if !ok {
413				file, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
414				if err != nil {
415					t.Fatal(err)
416				}
417				writer = shardWriter{file: file, enc: json.NewEncoder(file)}
418				writers[path] = writer
419			}
420			group := groups[(i/shards)%len(groups)]
421			entry := agent.SessionIndexEntry{
422				ID:           fmt.Sprintf("sess-%06d", i),
423				ProjectID:    projectID,
424				BeadID:       fmt.Sprintf("ddx-fixture-%04d", i%137),
425				Harness:      group.harness,
426				Provider:     group.provider,
427				Model:        group.model,
428				StartedAt:    ts,
429				EndedAt:      ts.Add(time.Duration(500+i%10_000) * time.Millisecond),
430				DurationMS:   500 + i%10_000,
431				CostUSD:      float64(i%1000) / 100_000,
432				CostPresent:  true,
433				InputTokens:  1000 + i%5000,
434				OutputTokens: 200 + i%2000,
435				Outcome:      "success",
436				BundlePath:   fmt.Sprintf(".ddx/executions/fixture-%06d", i),
437			}
438			if i%11 == 0 {
439				entry.Outcome = "failure"
440				entry.ExitCode = 1
441				entry.Detail = "fixture failure"
442			}
443			if err := writer.enc.Encode(entry); err != nil {
444				t.Fatal(err)
445			}
446		}
447	}
