449	func measureP95(iterations int, fn func()) time.Duration {
450		durations := make([]time.Duration, iterations)
451		for i := 0; i < iterations; i++ {
452			start := time.Now()
453			fn()
454			durations[i] = time.Since(start)
455		}
456		sort.Slice(durations, func(i, j int) bool { return durations[i] < durations[j] })
457		idx := int(float64(iterations)*0.95+0.999999) - 1
458		if idx < 0 {
459			idx = 0
460		}
461		if idx >= len(durations) {
462			idx = len(durations) - 1
463		}
464		return durations[idx]
465	}
