478	func graphqlPOSTForTestReturningBody(t *testing.T, h http.Handler, query string) []byte {
479		t.Helper()
480		body, err := json.Marshal(map[string]string{"query": query})
481		if err != nil {
482			t.Fatal(err)
483		}
484		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(body))
485		req.Header.Set("content-type", "application/json")
486		rec := httptest.NewRecorder()
487		h.ServeHTTP(rec, req)
488		if rec.Code != http.StatusOK {
