77	// StartWorker is the resolver for the startWorker field.
78	//
79	// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
80	// project's .ddx/config.yaml drives default harness/profile/effort/label
81	// values when the GraphQL input leaves them unset. Input fields are layered
82	// onto config as CLIOverrides — when present they win over the on-disk
83	// values. The resolved values are forwarded to ActionDispatcher (and ultimately
84	// to runWorker, which re-loads config to drive the loop's durable knobs like
85	// review_max_retries / no_progress_cooldown / heartbeat_interval). This
86	// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
87	// shadowed the on-disk config.
88	func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
89		if r.Actions == nil {
90			return nil, fmt.Errorf("work worker dispatcher is not configured")
91		}
92		projectRoot := r.projectRoot(ctx, input.ProjectID)
93	
94		overrides := config.CLIOverrides{}
95		if input.Harness != nil {
96			overrides.Harness = strings.TrimSpace(*input.Harness)
97		}
98		if input.Profile != nil {
99			overrides.Profile = strings.TrimSpace(*input.Profile)
100		}
101		if input.Effort != nil {
102			overrides.Effort = strings.TrimSpace(*input.Effort)
103		}
104		rcfg, _ := config.LoadAndResolve(projectRoot, overrides)
105	
106		args := map[string]string{}
107		if v := rcfg.Harness(); v != "" {
108			args["harness"] = v
109		}
110		profile := rcfg.Profile()
111		if profile == "" {
112			profile = "smart"
113		}
114		args["profile"] = profile
115		effort := rcfg.Effort()
116		if effort == "" {
117			effort = "medium"
118		}
119		args["effort"] = effort
120		if input.LabelFilter != nil && strings.TrimSpace(*input.LabelFilter) != "" {
121			args["label_filter"] = strings.TrimSpace(*input.LabelFilter)
122		}
123		mode := "watch"
124		if input.Mode != nil && strings.TrimSpace(*input.Mode) != "" {
125			mode = strings.TrimSpace(*input.Mode)
126		}
127		args["mode"] = mode
128		if input.IdleInterval != nil && strings.TrimSpace(*input.IdleInterval) != "" {
129			args["idle_interval"] = strings.TrimSpace(*input.IdleInterval)
130		} else if mode == "watch" {
131			args["idle_interval"] = "30s"
132		}
133		raw, err := json.Marshal(args)
134		if err != nil {
135			return nil, err
136		}
137		rawArgs := string(raw)
138		return r.Actions.DispatchWorker(ctx, "work", projectRoot, &rawArgs)
139	}
