298	// QueueSummary is the resolver for the queueSummary field.
299	// InProgress counts both beads with status==in_progress plus in-flight attempts
300	// from live run-state.json (for inline work).
301	func (r *queryResolver) QueueSummary(ctx context.Context, projectID string) (*QueueSummary, error) {
302		projectRoot := r.projectRoot(ctx, projectID)
303		store := projectBeadStore(projectRoot)
304		counts, err := store.Status()
305		if err != nil {
306			return nil, err
307		}
308	
309		// Count in-flight attempts from run-state.json as in-progress.
310		inProgressFromRunState := countInFlightAttempts(projectRoot)
311	
312		return &QueueSummary{
313			Ready:             counts.Ready,
314			Blocked:           counts.ExternalBlocked,
315			InProgress:        counts.InProgress + inProgressFromRunState,
316			OperatorAttention: counts.OperatorAttention,
317			DependencyWaiting: counts.DependencyWaiting,
318			ExternalBlocked:   counts.ExternalBlocked,
319			Cancelled:         counts.Cancelled,
320		}, nil
321	}
