323	// countInFlightAttempts returns the number of non-expired run-state.json files
324	// in the project, representing in-flight execution attempts.
325	func countInFlightAttempts(projectRoot string) int {
326		if projectRoot == "" {
327			return 0
328		}
329		runStateDir := filepath.Join(projectRoot, ddxroot.DirName, agent.RunStateDirName)
330		entries, err := os.ReadDir(runStateDir)
331		if err != nil {
332			return 0
333		}
334		now := time.Now().UTC()
335		count := 0
336		for _, entry := range entries {
337			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
338				continue
339			}
340			data, err := os.ReadFile(filepath.Join(runStateDir, entry.Name()))
341			if err != nil {
342				continue
343			}
344			var state agent.RunState
345			if err := json.Unmarshal(data, &state); err != nil {
346				continue
347			}
348			// Skip expired runs.
349			if !state.ExpiresAt.IsZero() && now.After(state.ExpiresAt) {
350				continue
351			}
352			count++
353		}
354		return count
355	}
