357	// QueueAndWorkersSummary backs the global drain indicator (ddx-b6cf025c).
358	// Returns zeros — not an error — for unknown or empty projects so the nav
359	// component can render without special-casing failures.
360	func (r *queryResolver) QueueAndWorkersSummary(ctx context.Context, projectID string) (*QueueAndWorkersSummary, error) {
361		out := &QueueAndWorkersSummary{}
362		// Only resolve ready beads when the projectID maps to a real project.
363		// Unknown IDs return zeros rather than falling back to WorkingDir so the
364		// indicator does not surface an unrelated project's queue depth.
365		if r.State != nil {
366			if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
367				store := projectBeadStore(proj.Path)
368				if ready, err := store.Ready(); err == nil {
369					out.ReadyBeads = len(ready)
370				}
371			}
372			workers := r.State.GetWorkersGraphQL(projectID)
373			out.TotalWorkers = len(workers)
374			for _, w := range workers {
375				if w != nil && w.State == "running" {
376					out.RunningWorkers++
377				}
378			}
379		}
380		// Surface the optional workers.max_count cap so the UI can pre-emptively
381		// disable the `+ Add worker` affordance rather than relying on a server
382		// error from workerDispatch (ddx-b6cf025c review finding).
383		if cfg, err := config.LoadWithWorkingDir(r.projectRoot(ctx, projectID)); err == nil && cfg != nil && cfg.Workers != nil && cfg.Workers.MaxCount != nil {
384			v := *cfg.Workers.MaxCount
385			out.MaxCount = &v
386		}
387		return out, nil
388	}
