458	// PaletteSearch is the resolver for the paletteSearch field.
459	func (r *queryResolver) PaletteSearch(ctx context.Context, query string) (*PaletteSearchResults, error) {
460		q := strings.TrimSpace(query)
461		out := &PaletteSearchResults{
462			Documents:  []*PaletteDocumentResult{},
463			Beads:      []*PaletteBeadResult{},
464			Actions:    []*PaletteActionResult{},
465			Navigation: []*PaletteNavigationResult{},
466		}
467		if q == "" {
468			return out, nil
469		}
470	
471		matches := collectPaletteMatches(q, r.workingDir(ctx))
472		sort.SliceStable(matches, func(i, j int) bool {
473			if matches[i].score != matches[j].score {
474				return matches[i].score < matches[j].score
475			}
476			return matches[i].sortKey < matches[j].sortKey
477		})
478		if len(matches) > paletteResultCap {
479			matches = matches[:paletteResultCap]
480		}
481		for _, match := range matches {
482			switch match.kind {
483			case "document":
484				out.Documents = append(out.Documents, &PaletteDocumentResult{Kind: "document", Path: match.id, Title: match.title})
