522	func DispatchPluginAction(workingDir string, name string, action string) (string, error) {
523		pluginActionMu.Lock()
524		defer pluginActionMu.Unlock()
525	
526		state, err := registry.LoadState()
527		if err != nil {
528			return "", fmt.Errorf("loading plugin state: %w", err)
529		}
530	
531		switch action {
532		case "install":
533			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
534				return "installed", nil
535			}
536			entry, err := installRegistryPlugin(workingDir, state, name)
537			if err != nil {
538				return "", err
539			}
540			if entry != nil && entry.VerifyFiles() {
541				return "installed", nil
542			}
543			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
544		case "update":
545			installed := state.FindInstalled(name)
546			if installed == nil {
547				return "", fmt.Errorf("plugin %q is not installed", name)
548			}
549			pkg, err := registry.BuiltinRegistry().Find(name)
550			if err != nil {
551				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
552			}
553			if installed.Version == pkg.Version && installed.VerifyFiles() {
554				return "installed", nil
555			}
556			entry, err := installRegistryPlugin(workingDir, state, name)
557			if err != nil {
558				return "", err
559			}
560			if entry != nil && entry.VerifyFiles() {
561				return "installed", nil
562			}
563			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
564		case "uninstall":
565			entry := state.FindInstalled(name)
566			if entry == nil {
567				return "", fmt.Errorf("plugin %q is not installed", name)
568			}
569			if err := registry.UninstallPackage(entry); err != nil {
570				return "", err
571			}
572			state.Remove(name)
573			if err := registry.SaveState(state); err != nil {
574				return "", fmt.Errorf("saving plugin state: %w", err)
575			}
576			return "uninstalled", nil
577		default:
578			return "", fmt.Errorf("unsupported plugin action %q", action)
579		}
580	}
