582	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
583		pkg, err := registry.BuiltinRegistry().Find(name)
584		if err != nil {
585			return nil, err
586		}
587	
588		origDir, _ := os.Getwd()
589		if workingDir != "" && origDir != workingDir {
590			if err := os.Chdir(workingDir); err != nil {
591				return nil, fmt.Errorf("entering project root: %w", err)
592			}
593			defer func() { _ = os.Chdir(origDir) }()
594		}
595	
596		entry, err := registry.InstallPackage(pkg, workingDir)
597		if err != nil {
598			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
599		}
600		state.AddOrUpdate(entry)
601		if err := registry.SaveState(state); err != nil {
602			return nil, fmt.Errorf("saving plugin state: %w", err)
603		}
604		return state.FindInstalled(name), nil
605	}
