607	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
608		dir := ddxroot.JoinProject(workingDir, "comparisons")
609		entries, err := os.ReadDir(dir)
610		if os.IsNotExist(err) {
611			return []comparisonDispatchRecord{}, nil
612		}
613		if err != nil {
614			return nil, err
615		}
616		records := make([]comparisonDispatchRecord, 0, len(entries))
617		for _, entry := range entries {
618			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
619				continue
620			}
621			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
622			if err != nil {
623				return nil, err
624			}
625			var record comparisonDispatchRecord
626			if err := json.Unmarshal(data, &record); err != nil {
627				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
628			}
629			if record.ID == "" {
630				continue
631			}
632			records = append(records, record)
633		}
634		sort.Slice(records, func(i, j int) bool {
635			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
636				return records[i].CreatedAt.After(records[j].CreatedAt)
637			}
638			return records[i].ID < records[j].ID
639		})
640		return records, nil
641	}
