752	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, _ registry.InstalledEntry) {
753		if workingDir == "" {
754			return
755		}
756		root := ddxroot.JoinProject(workingDir, "plugins", name)
757		if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
758			return
