761			info.DiskBytes = dirSize(root)
762		}
763		if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
764			if pkg.Version != "" {
765				info.Version = pkg.Version
766			}
767			if pkg.Description != "" {
768				info.Description = pkg.Description
769			}
770			if pkg.Type != "" {
771				info.Type = string(pkg.Type)
772			}
773			if pkg.Source != "" {
774				info.RegistrySource = pkg.Source
775			}
776			if len(pkg.Keywords) > 0 {
777				info.Keywords = append([]string(nil), pkg.Keywords...)
778			}
779			if manifest, err := json.Marshal(pkg); err == nil {
780				info.Manifest = strPtr(string(manifest))
781			}
782		}
783		info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
784		info.Prompts = uniqueStrings(append(info.Prompts, scanNamedChildren(root, []string{"prompts", "library/prompts"}, "")...))
785		info.Templates = uniqueStrings(append(info.Templates, scanNamedChildren(root, []string{"templates", "library/templates"}, "")...))
786	}
