788	func dirSize(root string) int {
789		var total int64
790		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
791			if err != nil || d.IsDir() {
792				return nil
793			}
794			if info, err := d.Info(); err == nil {
795				total += info.Size()
796			}
797			return nil
798		})
799		const maxInt32 = int64(1<<31 - 1)
800		if total > maxInt32 {
801			return int(maxInt32)
802		}
803		return int(total)
804	}
805	
806	func scanNamedChildren(root string, relDirs []string, marker string) []string {
807		var out []string
808		for _, rel := range relDirs {
809			base := filepath.Join(root, filepath.FromSlash(rel))
810			entries, err := os.ReadDir(base)
811			if err != nil {
812				continue
813			}
814			for _, entry := range entries {
815				if strings.HasPrefix(entry.Name(), ".") {
816					continue
817				}
818				if marker != "" {
819					if !entry.IsDir() {
820						continue
821					}
822					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
823						continue
824					}
825				}
826				out = append(out, entry.Name())
827			}
828		}
829		return out
830	}
