847	func (r *queryResolver) efficacySnapshot(ctx context.Context, since, until, projectID, promptSHA *string) (efficacySnapshot, error) {
848		projectRoot := r.workingDir(ctx)
849		if projectID != nil && strings.TrimSpace(*projectID) != "" {
850			projectRoot = r.projectRoot(ctx, strings.TrimSpace(*projectID))
851		}
852		startedAfter, err := parseOptionalEfficacyTime("since", since)
853		if err != nil {
854			return efficacySnapshot{}, err
855		}
856		startedBefore, err := parseOptionalEfficacyTime("until", until)
857		if err != nil {
858			return efficacySnapshot{}, err
859		}
860		logDir := agent.SessionLogDirForWorkDir(projectRoot)
861		query := agent.SessionIndexQuery{
862			StartedAfter:  startedAfter,
863			StartedBefore: startedBefore,
864		}
865		if promptSHA != nil {
866			query.PromptSHA = strings.TrimSpace(*promptSHA)
867		}
868		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore, query.PromptSHA)
869		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
870		if err != nil {
871			return efficacySnapshot{}, err
872		}
873		sessionEfficacyCache.Lock()
874		if sessionEfficacyCache.byQuery == nil {
875			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
876		}
877		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
878			sessionEfficacyCache.Unlock()
879			return cached.snapshot, nil
880		}
881		sessionEfficacyCache.Unlock()
882	
883		entries, err := agent.ReadSessionIndex(logDir, query)
884		if err != nil {
885			return efficacySnapshot{}, err
886		}
887		snap := buildSessionIndexEfficacySnapshot(entries)
888		sessionEfficacyCache.Lock()
889		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
890		sessionEfficacyCache.Unlock()
891		return snap, nil
892	}
