894	func sessionEfficacyCacheKey(logDir string, startedAfter, startedBefore *time.Time, promptSHA string) string {
895		return strings.Join([]string{logDir, timeKey(startedAfter), timeKey(startedBefore), strings.TrimSpace(promptSHA)}, "|")
896	}
897	
898	func timeKey(t *time.Time) string {
899		if t == nil {
900			return ""
901		}
902		return t.UTC().Format(time.RFC3339Nano)
903	}
904	
905	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
906		files, err := agent.SessionIndexShardFiles(logDir, query)
907		if err != nil {
908			return "", err
909		}
910		parts := make([]string, 0, len(files))
911		for _, file := range files {
912			info, err := os.Stat(file)
913			if os.IsNotExist(err) {
914				continue
915			}
916			if err != nil {
917				return "", err
918			}
919			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
920		}
921		return strings.Join(parts, "|"), nil
922	}
923	
924	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
925		if raw == nil || strings.TrimSpace(*raw) == "" {
926			return nil, nil
927		}
928		value := strings.TrimSpace(*raw)
929		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
930			if parsed, err := time.Parse(layout, value); err == nil {
931				utc := parsed.UTC()
932				return &utc, nil
933			}
934		}
935		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
936	}
