938	type sessionEfficacyAttempt struct {
939		RowKey       string
940		BeadID       string
941		Outcome      string
942		Harness      string
943		Provider     string
944		Model        string
945		InputTokens  int
946		OutputTokens int
947		DurationMs   int
948		CostUsd      *float64
949		EvidencePath string
950		CreatedAt    time.Time
951	}
952	
953	func buildSessionIndexEfficacySnapshot(entries []agent.SessionIndexEntry) efficacySnapshot {
954		grouped := map[string][]sessionEfficacyAttempt{}
955		for _, entry := range entries {
956			attempt := efficacyAttemptFromSession(entry)
957			if attempt.RowKey == "" {
958				continue
959			}
960			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
961		}
962		rows := make([]*EfficacyRow, 0, len(grouped))
963		attemptDetails := map[string][]*EfficacyAttempt{}
964		now := time.Now().UTC()
965		for rowKey, group := range grouped {
966			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
967			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
968			var inputTokens, outputTokens, durations []int
969			var costs []float64
970			var successes int
971			for _, attempt := range group {
972				if attempt.Outcome == "succeeded" {
973					successes++
974				}
975				inputTokens = append(inputTokens, attempt.InputTokens)
976				outputTokens = append(outputTokens, attempt.OutputTokens)
977				durations = append(durations, attempt.DurationMs)
978				if attempt.CostUsd != nil {
979					costs = append(costs, *attempt.CostUsd)
980				}
981				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
982					BeadID:            attempt.BeadID,
983					Outcome:           attempt.Outcome,
984					DurationMs:        attempt.DurationMs,
985					CostUsd:           attempt.CostUsd,
986					EvidenceBundleURL: attempt.EvidencePath,
987				})
988			}
989			sparkline := buildEfficacySparkline(group, now)
990			parts := strings.Split(rowKey, "|")
991			row := &EfficacyRow{
992				RowKey:             rowKey,
993				Harness:            parts[0],
994				Provider:           parts[1],
995				Model:              parts[2],
996				Attempts:           len(group),
997				Successes:          successes,
998				SuccessRate:        float64(successes) / float64(len(group)),
999				MedianInputTokens:  medianInt(inputTokens),
1000				MedianOutputTokens: medianInt(outputTokens),
1001				MedianDurationMs:   medianInt(durations),
1002				MedianCostUsd:      medianFloatPtr(costs),
1003				Sparkline:          sparkline,
1004			}
1005			if row.SuccessRate < efficacyWarningFloor {
1006				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
1007			}
1008			rows = append(rows, row)
1009		}
1010		sort.Slice(rows, func(i, j int) bool {
1011			if rows[i].SuccessRate != rows[j].SuccessRate {
1012				return rows[i].SuccessRate > rows[j].SuccessRate
1013			}
1014			return rows[i].RowKey < rows[j].RowKey
1015		})
1016	
1017		return efficacySnapshot{rows: rows, attempts: attemptDetails}
1018	}
1019	
1020	func buildEfficacySparkline(attempts []sessionEfficacyAttempt, now time.Time) []int {
1021		if len(attempts) == 0 {
1022			return nil
1023		}
1024		if now.IsZero() {
1025			now = time.Now().UTC()
1026		}
1027		end := now.UTC().Truncate(time.Hour).Add(time.Hour)
1028		start := end.Add(-24 * time.Hour)
1029		const bucketSize = time.Hour
1030		bucketCount := int(end.Sub(start) / bucketSize)
1031		if bucketCount <= 0 {
1032			return nil
1033		}
1034		successes := make([]int, bucketCount)
1035		attemptCounts := make([]int, bucketCount)
1036		nonEmpty := 0
1037		for _, attempt := range attempts {
1038			ts := attempt.CreatedAt.UTC()
1039			if ts.Before(start) || !ts.Before(end) {
1040				continue
1041			}
1042			idx := int(ts.Sub(start) / bucketSize)
1043			if idx < 0 || idx >= bucketCount {
1044				continue
1045			}
1046			attemptCounts[idx]++
1047			if attempt.Outcome == "succeeded" {
1048				successes[idx]++
1049			}
1050		}
1051		sparkline := make([]int, bucketCount)
1052		for i := range sparkline {
1053			if attemptCounts[i] == 0 {
1054				continue
1055			}
1056			nonEmpty++
1057			sparkline[i] = (successes[i]*100 + attemptCounts[i]/2) / attemptCounts[i]
1058		}
1059		if nonEmpty < 6 {
1060			return nil
1061		}
1062		return sparkline
1063	}
