1065	func efficacyAttemptFromSession(entry agent.SessionIndexEntry) sessionEfficacyAttempt {
1066		model := firstNonEmpty(entry.Model, "unknown")
1067		provider := firstNonEmpty(entry.Provider, providerFromModel(model), entry.Harness, "unknown")
1068		harness := firstNonEmpty(entry.Harness, provider, "unknown")
1069		cost := efficacyCost(entry)
1070		outcome := efficacyOutcome(entry)
1071		return sessionEfficacyAttempt{
1072			RowKey:       strings.Join([]string{harness, provider, model}, "|"),
1073			BeadID:       entry.BeadID,
1074			Outcome:      outcome,
1075			Harness:      harness,
1076			Provider:     provider,
1077			Model:        model,
1078			InputTokens:  entry.InputTokens,
1079			OutputTokens: entry.OutputTokens,
1080			DurationMs:   entry.DurationMS,
1081			CostUsd:      cost,
1082			EvidencePath: efficacyEvidencePath(entry),
1083			CreatedAt:    entry.StartedAt,
1084		}
1085	}
