1186	func paletteScore(query string, fields ...string) (int, bool) {
1187		q := strings.ToLower(strings.TrimSpace(query))
1188		if q == "" {
1189			return 0, false
1190		}
1191		terms := strings.Fields(q)
1192		best := 1000
1193		for _, field := range fields {
1194			f := strings.ToLower(field)
1195			if strings.HasPrefix(f, q) {
1196				best = min(best, 0)
1197				continue
1198			}
1199			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
1200				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
1201			}) {
1202				if strings.HasPrefix(part, q) {
1203					best = min(best, 1)
1204				}
1205			}
1206			allTerms := true
1207			for _, term := range terms {
1208				if !strings.Contains(f, term) {
1209					allTerms = false
1210					break
1211				}
1212			}
1213			if allTerms {
1214				best = min(best, 2)
1215			}
1216		}
1217		if best == 1000 {
1218			return 0, false
1219		}
1220		return best, true
1221	}
